insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'Doctor is related to Hospital in the same way as Teacher is related to:', 'Doctor, Hospital से related है उसी तरह Teacher किससे related है?', 'Identify the relation Doctor -> Hospital; applying the same relation gives Teacher -> School. Therefore, answer = School.', 'Analogy questions test relation transfer. The word pair relation must remain identical in the second pair. Final answer is School.', 'Doctor -> Hospital relation पहचानें; same relation लगाने पर Teacher -> School मिलता है। अतः answer = School।', 'Analogy questions relation transfer test करते हैं। Second pair में relation same रहना चाहिए। Final answer School है।', 'MEDIUM', array['reasoning','analogy']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Hospital', 'Hospital', false, 'Copied the first pair''s second term instead of applying the same relation to Teacher.', 'First pair का second term copy कर दिया, Teacher पर same relation apply नहीं किया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Doctor', 'Doctor', false, 'Picked the first pair''s first term and broke the analogy relation.', 'First pair का first term चुन लिया और analogy relation टूट गया।');
