insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 11, 'Pen is related to Write in the same way as Knife is related to:', 'Pen, Write से related है उसी तरह Knife किससे related है?', 'Identify the relation Pen -> Write; applying the same relation gives Knife -> Cut. Therefore, answer = Cut.', 'Analogy questions test relation transfer. The word pair relation must remain identical in the second pair. Final answer is Cut.', 'Pen -> Write relation पहचानें; same relation लगाने पर Knife -> Cut मिलता है। अतः answer = Cut।', 'Analogy questions relation transfer test करते हैं। Second pair में relation same रहना चाहिए। Final answer Cut है।', 'MEDIUM', array['reasoning','analogy']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
